function solve(n: number): string {
    function convertToBase(num: number, base: number): string {
        if (num === 0) return "0";
        let result = "";
        while (num > 0) {
            let remainder = num % base;
            let c: string;
            if (remainder < 10) {
                c = remainder.toString();
            } else {
                c = String.fromCharCode(65 + remainder - 10);
            }
            result = c + result;
            num = Math.floor(num / base);
        }
        return result;
    }
    const n2 = n * n;
    const n3 = n2 * n;
    const hexPart = convertToBase(n2, 16);
    const base36Part = convertToBase(n3, 36);
    return hexPart + base36Part;
}
```

